mkdir -p /tmp/sv-d9f48b21284a423db89c8c5b06b2da52/typed-meta && cd /tmp/sv-d9f48b21284a423db89c8c5b06b2da52/typed-meta && dotnet new console --framework net11.0 -o . --force -n TypedMeta >/dev/null 2>&1 && cat > Program.cs << 'EOF'
using System;
using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions { TypeInfoResolver = new DefaultJsonTypeInfoResolver() };

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
//    Use an empty resolver so nothing is resolvable.
var empty = new JsonSerializerOptions { TypeInfoResolver = JsonTypeInfoResolver.Combine() };

bool found = empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"TryGetTypeInfo on empty resolver => found: {found}, info: {info?.Type.Name ?? "(null)"}");

// Also show success path of TryGetTypeInfo
bool found2 = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2);
Console.WriteLine($"TryGetTypeInfo on real resolver => found: {found2}, info: {info2?.Type.Name ?? "(null)"}");

public record Person(string Name, int Age);
EOF
dotnet run

